### 3. Score Calibration Tests
```rust
#[test]
fn test_scores_are_bounded() {
    let reranker = create_test_reranker();
    let query = "test";
    let docs = vec!["relevant doc", "irrelevant doc"];
    let scores = reranker.rerank(query, &docs).unwrap();

    for (i, score) in scores.iter().enumerate() {
        assert!(score.is_finite(), "Score {} should be finite, got {}", i, score);
        // Most rerankers output logits or 0-1 range
        assert!(*score > -100.0 && *score < 100.0,
            "Score {} seems uncalibrated: {}", i, score);
    }
}

#[test]
fn test_scores_are_consistent_across_calls() {
    let reranker = create_test_reranker();
    let query = "test query";
    let docs = vec!["document one", "document two"];

    let scores1 = reranker.rerank(query, &docs).unwrap();
    let scores2 = reranker.rerank(query, &docs).unwrap();

    for (s1, s2) in scores1.iter().zip(scores2.iter()) {
        assert!((s1 - s2).abs() < 1e-5, "Scores should be deterministic: {} vs {}", s1, s2);
