### 6. Pipeline Integration Tests (Embedder → Retrieve → Rerank)
```rust
/// Full pipeline test: embed query → find top-K → rerank → verify quality lift
#[test]
fn test_full_search_pipeline_with_reranking() {
    // Setup: index a small test corpus
    let corpus = vec![
        ("doc1", "Rust programming language for systems development and safety"),
        ("doc2", "Python machine learning with TensorFlow and PyTorch"),
        ("doc3", "JavaScript React frontend web development"),
        ("doc4", "The weather is nice today with clear skies"),
        ("doc5", "Rust ownership and borrowing ensures memory safety without GC"),
        ("doc6", "Recipe for chocolate chip cookies with butter and sugar"),
    ];

    let embedder = create_test_embedder();  // Uses baseline embedder
    let reranker = create_test_reranker();

    // Step 1: Embed all docs
    let doc_texts: Vec<&str> = corpus.iter().map(|(_, t)| *t).collect();
    let doc_embeddings = embedder.embed(&doc_texts).unwrap();

    // Step 2: Embed query and retrieve top-K by cosine similarity
    let query = "memory safe systems programming";
    let query_embedding = embedder.embed(&[query]).unwrap();

    let mut similarities: Vec<(usize, f32)> = doc_embeddings.iter()
        .enumerate()
        .map(|(i, emb)| (i, cosine_similarity(&query_embedding[0], emb)))
        .collect();
    similarities.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());

    let top_k = 4;  // Retrieve top-4
    let retrieved: Vec<&str> = similarities[..top_k].iter()
        .map(|(i, _)| doc_texts[*i])
        .collect();

    info!("Retrieved (embedding only):");
    for (rank, (idx, score)) in similarities[..top_k].iter().enumerate() {
        info!("  {}: [{}] score={:.3} \"{}\"", rank+1, corpus[*idx].0, score, &doc_texts[*idx][..40]);
    }

    // Step 3: Rerank the retrieved docs
    let rerank_scores = reranker.rerank(query, &retrieved).unwrap();

    let mut reranked: Vec<(usize, f32)> = rerank_scores.iter()
        .enumerate()
        .map(|(i, &s)| (i, s))
        .collect();
    reranked.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());

    info!("After reranking:");
    for (rank, (idx, score)) in reranked.iter().enumerate() {
        info!("  {}: score={:.3} \"{}\"", rank+1, score, &retrieved[*idx][..40]);
    }

    // Verify: Rust docs should be top-2 after reranking
    let top_reranked_doc = retrieved[reranked[0].0];
    assert!(top_reranked_doc.contains("Rust") || top_reranked_doc.contains("memory safety"),
        "Top reranked doc should be about Rust/memory safety, got: {}", top_reranked_doc);
}

/// Test that reranking provides quality lift over embedding-only retrieval
#[test]
fn test_reranking_provides_quality_lift() {
    let corpus = load_test_corpus();  // Uses test fixture subset
    let embedder = create_test_embedder();
    let reranker = create_test_reranker();

    let mut embed_ndcg_sum = 0.0;
    let mut rerank_ndcg_sum = 0.0;
    let query_count = corpus.queries.len().min(20);  // Cap for test speed

    for query in corpus.queries.iter().take(query_count) {
        // Embedding retrieval
        let query_emb = embedder.embed(&[query.text.as_str()]).unwrap();
        let mut results = brute_force_topk(&query_emb[0], &corpus.docs, 20);

        let embed_ndcg = ndcg_at_k(&results, &query.relevants, 10);

        // Rerank top-20
        let result_texts: Vec<&str> = results.iter().map(|r| r.text.as_str()).collect();
        let scores = reranker.rerank(&query.text, &result_texts).unwrap();

        // Reorder by rerank scores
        let mut scored: Vec<(usize, f32)> = scores.iter().enumerate()
            .map(|(i, &s)| (i, s)).collect();
        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
        let reranked_results: Vec<_> = scored.iter().map(|(i, _)| results[*i].clone()).collect();

        let rerank_ndcg = ndcg_at_k(&reranked_results, &query.relevants, 10);

        embed_ndcg_sum += embed_ndcg;
        rerank_ndcg_sum += rerank_ndcg;

        info!("Query \"{}\": embed NDCG@10={:.3}, rerank NDCG@10={:.3} (lift={:.1}%)",
            &query.text[..30.min(query.text.len())],
            embed_ndcg, rerank_ndcg,
            (rerank_ndcg - embed_ndcg) / embed_ndcg.max(0.001) * 100.0);
    }

    let avg_embed = embed_ndcg_sum / query_count as f64;
    let avg_rerank = rerank_ndcg_sum / query_count as f64;
    let lift_pct = (avg_rerank - avg_embed) / avg_embed.max(0.001) * 100.0;

    info!("Average NDCG@10: embed={:.3}, rerank={:.3}, lift={:.1}%", avg_embed, avg_rerank, lift_pct);

    // Reranking should provide positive lift (at least 2% average improvement)
    assert!(avg_rerank >= avg_embed,
        "Reranking should not degrade quality: {:.3} vs {:.3}", avg_rerank, avg_embed);
    assert!(lift_pct > 2.0,
        "Reranking should provide >2% lift, got {:.1}%", lift_pct);
}

/// Test the wire reranker integration (bd-ylsp: RerankStep in search pipeline)
#[test]
fn test_wire_reranker_stable_sort() {
    use crate::model::SearchResult;

    let reranker = create_test_reranker();

    // Create search results with initial scores
    let mut results = vec![
        SearchResult { id: "1".into(), text: "Rust is great".into(), score: 0.9, .. },
        SearchResult { id: "2".into(), text: "Python is popular".into(), score: 0.85, .. },
        SearchResult { id: "3".into(), text: "Go is fast".into(), score: 0.8, .. },
    ];

    // Apply reranking step (as bd-ylsp defines)
    let texts: Vec<&str> = results.iter().map(|r| r.text.as_str()).collect();
    let rerank_scores = reranker.rerank("systems programming", &texts).unwrap();

    // Attach rerank scores and sort (stable sort: rerank_score desc, then original score desc)
    let mut scored: Vec<(usize, f32, f32)> = results.iter().enumerate()
        .map(|(i, r)| (i, rerank_scores[i], r.score))
        .collect();
    scored.sort_by(|a, b| {
        b.1.partial_cmp(&a.1)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then(b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal))
    });

    // Verify stable sort: if rerank scores are equal, original order preserved
    info!("Wire reranker ordering:");
    for (rank, (idx, rscore, oscore)) in scored.iter().enumerate() {
        info!("  {}: id={} rerank={:.3} orig={:.3}", rank+1, results[*idx].id, rscore, oscore);
    }

    // Rust should likely rank highest for "systems programming"
    let top_id = &results[scored[0].0].id;
    info!("Top result: id={}", top_id);
}

