    pub async fn spawn_same_socket(&self) -> anyhow::Result<Self>;

    /// Gracefully stop the daemon
    pub async fn stop(&mut self) -> anyhow::Result<()>;

    /// Check if daemon process is still running
    pub fn is_running(&mut self) -> bool;
}

