// tests/daemon_stress.rs

#[tokio::test]
async fn test_concurrent_embed_requests() {
    let daemon = DaemonProcess::spawn().await.unwrap();
    let client = DaemonClient::with_socket_path(daemon.socket_path.clone());

    // Spawn 20 concurrent embed requests
    let handles: Vec<_> = (0..20).map(|i| {
        let client = client.clone();
        tokio::spawn(async move {
            let start = Instant::now();
            let result = client.embed(&[format!("text {i}")], "hash", None).await;
            (i, result, start.elapsed())
        })
    }).collect();

    let results: Vec<_> = futures::future::join_all(handles).await;

    for (i, result, elapsed) in results.into_iter().map(|r| r.unwrap()) {
        tracing::info!(request_id = i, elapsed_ms = elapsed.as_millis(), "request complete");
        assert!(result.is_ok(), "Request {i} failed: {:?}", result);
    }
}

#[tokio::test]
async fn test_in_flight_limit_enforcement() {
    let daemon = DaemonProcess::spawn().await.unwrap();

    // Create 70 simultaneous connections (exceeds MAX_IN_FLIGHT=64)
    let handles: Vec<_> = (0..70).map(|i| {
        let socket = daemon.socket_path.clone();
        tokio::spawn(async move {
            let client = DaemonClient::with_socket_path(socket);
            // Use slow embed to keep connection open
            let result = client.embed(&[format!("text {i}")], "minilm", None).await;
            (i, result)
        })
    }).collect();

    let results: Vec<_> = futures::future::join_all(handles).await;

    // Some should succeed, some should get OVERLOADED error
    let successes = results.iter().filter(|r| r.as_ref().unwrap().1.is_ok()).count();
    let overloaded = results.iter().filter(|r| {
        matches!(r.as_ref().unwrap().1.as_ref().err(), Some(e) if e.to_string().contains("overloaded"))
    }).count();

    tracing::info!(successes, overloaded, "In-flight limit test results");
    assert!(successes <= 64, "Should not exceed MAX_IN_FLIGHT");
    assert!(overloaded > 0, "Should have rejected some requests");
}

#[tokio::test]
async fn test_no_resource_leak_under_load() {
    let daemon = DaemonProcess::spawn().await.unwrap();
    let client = DaemonClient::with_socket_path(daemon.socket_path.clone());

    // Initial RSS
    let status_before = client.status().await.unwrap();
    let rss_before = status_before.rss_mb;

    // Run 1000 sequential requests
    for i in 0..1000 {
        let _ = client.embed(&["test"], "hash", None).await;
        if i % 100 == 0 {
            tracing::info!(request = i, "Progress");
        }
    }

    // Final RSS
    let status_after = client.status().await.unwrap();
    let rss_after = status_after.rss_mb;
    let rss_growth = rss_after - rss_before;

    tracing::info!(
        rss_before_mb = rss_before,
        rss_after_mb = rss_after,
        growth_mb = rss_growth,
        "Memory usage after 1000 requests"
    );

    // RSS growth should be minimal (< 50MB)
    assert!(rss_growth < 50.0, "Memory grew too much: {rss_growth} MB");
}
